  1→import { useState } from "react";
  2→import { Outlet, createRootRoute, createRoute, createRouter, redirect, useNavigate } from "@tanstack/react-router";
  3→import { authClient } from "./lib/auth-client";
  4→import { WorkspaceGuard } from "./components/layout/WorkspaceGuard";
  5→import { WorkspaceSidebar } from "./components/layout/WorkspaceSidebar";
  6→import { SearchOverlay } from "./components/search/SearchOverlay";
  7→import { useWorkspace } from "./hooks/use-workspace";
  8→import { useWorkspaceState } from "./stores/workspace-state";
  9→import { ChatPage } from "./routes/chat-page";
 10→import { GraphPage } from "./routes/graph-page";
 11→import { HomePage } from "./routes/home-page";
 12→import { ReviewPage } from "./routes/review-page";
 13→import { LearningsPage } from "./routes/learnings-page";
 14→import { PoliciesPage } from "./components/policy/PoliciesPage";
 15→import { PolicyDetailPage } from "./components/policy/PolicyDetailPage";
 16→import { SignInPage } from "./routes/sign-in-page";
 17→import { ConsentPage } from "./routes/consent-page";
 18→import { Button } from "./components/ui/button";
 19→import { Badge } from "./components/ui/badge";
 20→import { Search } from "lucide-react";
 21→
 22→function AppShell() {
 23→  const workspace = useWorkspace();
 24→  const sidebar = useWorkspaceState((s) => s.sidebar);
 25→  const sidebarHandlers = useWorkspaceState((s) => s.sidebarHandlers);
 26→  const workspaceName = useWorkspaceState((s) => s.workspaceName);
 27→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 28→  const navigate = useNavigate();
 29→  const [searchOpen, setSearchOpen] = useState(false);
 30→
 31→  function handleNewConversation() {
 32→    if (sidebarHandlers) {
 33→      sidebarHandlers.onNewConversation();
 34→    }
 35→    void navigate({ to: "/chat" });
 36→  }
 37→
 38→  function handleSelectConversation(conversationId: string) {
 39→    if (sidebarHandlers) {
 40→      sidebarHandlers.onSelectConversation(conversationId);
 41→    }
 42→    void navigate({ to: "/chat/$conversationId", params: { conversationId } });
 43→  }
 44→
 45→  return (
 46→    <WorkspaceGuard
 47→      isReady={workspace.isReady}
 48→      isBootstrapping={workspace.isBootstrapping}
 49→      isCreatingWorkspace={workspace.isCreatingWorkspace}
 50→      canCreateWorkspace={workspace.canCreateWorkspace}
 51→      createWorkspaceName={workspace.createWorkspaceName}
 52→      createWorkspaceDescription={workspace.createWorkspaceDescription}
 53→      createWorkspaceRepoPath={workspace.createWorkspaceRepoPath}
 54→      errorMessage={workspace.errorMessage}
 55→      setCreateWorkspaceName={workspace.setCreateWorkspaceName}
 56→      setCreateWorkspaceDescription={workspace.setCreateWorkspaceDescription}
 57→      setCreateWorkspaceRepoPath={workspace.setCreateWorkspaceRepoPath}
 58→      onCreateWorkspace={workspace.onCreateWorkspace}
 59→    >
 60→      <div className="flex h-screen overflow-hidden bg-background text-foreground">
 61→        <WorkspaceSidebar
 62→          sidebar={sidebar}
 63→          activeConversationId={sidebarHandlers?.activeConversationId}
 64→          isLoading={sidebarHandlers?.isLoading ?? false}
 65→          onNewConversation={handleNewConversation}
 66→          onSelectConversation={handleSelectConversation}
 67→        />
 68→        <div className="flex flex-1 flex-col overflow-hidden">
 69→          <div className="flex h-10 shrink-0 items-center gap-2 border-b border-border bg-card px-4">
 70→            <span className="text-sm font-semibold text-foreground">{workspaceName}</span>
 71→            {onboardingState === "active" ? (
 72→              <Badge variant="secondary">Setting up</Badge>
 73→            ) : onboardingState === "summary_pending" ? (
 74→              <Badge variant="secondary">Review setup</Badge>
 75→            ) : undefined}
 76→            <Button
 77→              variant="outline"
 78→              size="xs"
 79→              className="ml-auto gap-1.5 text-muted-foreground"
 80→              onClick={() => setSearchOpen(true)}
 81→            >
 82→              <Search className="size-3" />
 83→              Search...
 84→            </Button>
 85→          </div>
 86→          <div className="flex-1 overflow-y-auto">
 87→            <Outlet />
 88→          </div>
 89→        </div>
 90→      </div>
 91→      {searchOpen ? <SearchOverlay onClose={() => setSearchOpen(false)} /> : undefined}
 92→    </WorkspaceGuard>
 93→  );
 94→}
 95→
 96→// Root route: bare outlet for public/authenticated split
 97→const rootRoute = createRootRoute({
 98→  component: () => <Outlet />,
 99→});
100→
101→// Public routes (no auth required)
102→const signInRoute = createRoute({
103→  getParentRoute: () => rootRoute,
104→  path: "/sign-in",
105→  component: SignInPage,
106→});
107→
108→const consentRoute = createRoute({
109→  getParentRoute: () => rootRoute,
110→  path: "/consent",
111→  component: ConsentPage,
112→});
113→
114→// Authenticated layout — checks session before rendering
115→const authLayout = createRoute({
116→  getParentRoute: () => rootRoute,
117→  id: "authenticated",
118→  component: AppShell,
119→  beforeLoad: async ({ location }) => {
120→    const { data } = await authClient.getSession();
121→    if (!data) {
122→      throw redirect({
123→        to: "/sign-in",
124→        search: { redirectTo: location.href },
125→      });
126→    }
127→  },
128→});
129→
130→const homeRoute = createRoute({
131→  getParentRoute: () => authLayout,
132→  path: "/",
133→  component: HomePage,
134→});
135→
136→type ChatSearch = { message?: string };
137→
138→const validateChatSearch = (search: Record<string, unknown>): ChatSearch => ({
139→  ...(typeof search.message === "string" ? { message: search.message } : {}),
140→});
141→
142→const chatRoute = createRoute({
143→  getParentRoute: () => authLayout,
144→  path: "/chat",
145→  component: ChatPage,
146→  validateSearch: validateChatSearch,
147→});
148→
149→const chatConversationRoute = createRoute({
150→  getParentRoute: () => authLayout,
151→  path: "/chat/$conversationId",
152→  component: ChatPage,
153→  validateSearch: validateChatSearch,
154→});
155→
156→const graphRoute = createRoute({
157→  getParentRoute: () => authLayout,
158→  path: "/graph",
159→  component: GraphPage,
160→});
161→
162→const reviewRoute = createRoute({
163→  getParentRoute: () => authLayout,
164→  path: "/review/$sessionId",
165→  component: ReviewPage,
166→});
167→
168→const learningsRoute = createRoute({
169→  getParentRoute: () => authLayout,
170→  path: "/learnings",
171→  component: LearningsPage,
172→});
173→
174→const policiesRoute = createRoute({
175→  getParentRoute: () => authLayout,
176→  path: "/policies",
177→  component: PoliciesPage,
178→});
179→
180→const policyDetailRoute = createRoute({
181→  getParentRoute: () => authLayout,
182→  path: "/policies/$policyId",
183→  component: PolicyDetailPage,
184→});
185→
186→const routeTree = rootRoute.addChildren([
187→  signInRoute,
188→  consentRoute,
189→  authLayout.addChildren([homeRoute, chatRoute, chatConversationRoute, graphRoute, reviewRoute, learningsRoute, policiesRoute, policyDetailRoute]),
190→]);
191→
192→export const router = createRouter({ routeTree });
193→
194→declare module "@tanstack/react-router" {
195→  interface Register {
196→    router: typeof router;
197→  }
198→}
